Nh(a){return"Essayer "+a},
gNg(){return"D'apr\xe8s ton niveau, tu pourrais aimer cette collection."},
gNe(){return"Tu n'as pas encore crois\xe9 toutes les r\xe8gles \u2014 continue \xe0 jouer pour les d\xe9couvrir une par une."},
gNf(){return"Choisir une autre collection"},
gG6(){return"Effacer toutes les statistiques"},
gGm(){return"Rejouer l'onboarding"},
gGo(){return"Rejouer l'onboarding ?"},
gGn(){return"Les explications de chaque r\xe8gle r\xe9appara\xeetront au fur et \xe0 mesure de tes parties. Tes statistiques de jeu sont conserv\xe9es."},
gG8(){return"Effacer toutes les statistiques ?"},
gG7(){return"Tout l'historique de jeu sera supprim\xe9 : temps, notes, statuts jou\xe9/pass\xe9. Cette action est irr\xe9versible."},
gGs(){return"Toutes les statistiques ont \xe9t\xe9 effac\xe9es."},
gv_(){return"Certaines contraintes ne sont pas valides."},
xo(a){return""+a+" erreurs."},
gOS(){return"Puzzle en cours"},
gOT(){return"Biblioth\xe8que"},
